import "../quiz_question.dart";

const _subject = "Literature in English";

QuizQuestion _q(String text, List<String> options, String correct, String explanation) {
  return QuizQuestion(
    subject: _subject,
    text: text,
    options: options,
    correctIndex: options.indexOf(correct),
    explanation: explanation,
  );
}

/// Obafemi Awolowo University (OAU) Post-UTME elective bank for Literature
/// in English — 100 medium-to-hard questions covering literary
/// appreciation/terminology, African and non-African drama, African and
/// non-African prose, and African and non-African poetry. Favours
/// well-known/classic texts (Shakespeare, Achebe, Soyinka and similar) so
/// the facts tested are reliable rather than obscure plot detail. This is a
/// general practice set, not an official OAU past-question paper.
List<QuizQuestion> buildOauLiteratureQuestions() {
  return [
    ..._literaryAppreciation,
    ..._africanDrama,
    ..._nonAfricanDrama,
    ..._africanProse,
    ..._nonAfricanProse,
    ..._africanPoetry,
    ..._nonAfricanPoetry,
  ];
}

